flow.set("processDone", false);
flow.set("subCount", 0);
flow.set("idNo", 0);
flow.set("filteredNo", 0);
flow.set("outgoingCostMap", {});
flow.set("csvIndex", {});

return [
  { payload: Date.now() },
  { payload: "No.,ID,TIMESTAMP\n" },
  { payload: "No.,Timestamp,Sequence Number,Attribute,Status,Data Type,Data Value\n" },
  { payload: "No.,Source,Destination,Cost\n" }
];

let rows;
let index = flow.get("csvIndex") || {};

if (Array.isArray(msg.payload)) {
  rows = msg.payload;
  index = {};
} else {
  rows = [msg.payload];
}

for (const row of rows) {
  if (!row) {
    continue;
  }
  const n = Number(row["Packet Number"]);
  if (Number.isFinite(n)) {
    index[n] = row;
  }
}

const count = Object.keys(index).length;
flow.set("csvIndex", index);

return { payload: `CSV index ready: ${count} rows` };

let no = flow.get("idNo") || 0;
if (no >= 200) {
  return null;
}

no += 1;
flow.set("idNo", no);

const id = Math.floor(Math.random() * 30001);
const ts = Math.floor(Date.now() / 1000);
const payload = { id, timestamp: ts };

return [
  { topic: "challenge3/id_generator", payload: JSON.stringify(payload) },
  { payload: `${no},${id},${ts}\n` }
];

if (flow.get("processDone")) {
  return null;
}

let data = msg.payload;
if (typeof data === "string") {
  try {
    data = JSON.parse(data);
  } catch (e) {
    return null;
  }
}

if (typeof data !== "object" || data === null || data.id === undefined) {
  return null;
}

const id = Number(data.id);
if (!Number.isFinite(id)) {
  return null;
}

let count = flow.get("subCount") || 0;
count += 1;
flow.set("subCount", count);

if (count > 200) {
  flow.set("processDone", true);
  return null;
}
if (count === 200) {
  flow.set("processDone", true);
}

const idInt = Math.trunc(id);

msg.sub_id = idInt;
msg.sub_timestamp = Number.isFinite(Number(data.timestamp))
  ? Math.trunc(Number(data.timestamp))
  : Math.floor(Date.now() / 1000);
msg.sub_count = count;
msg.n = ((idInt % 5218) + 5218) % 5218;

return msg;

const packetIndex = flow.get("csvIndex") || {};
const packet = packetIndex[msg.n];
if (!packet) return [null, null, null, null, null, null, null];

function parseCommand(raw) {
  const src = String(raw ?? "").trim();
  if (!src) return {};

  const sanitize = text => text
    .replace(/,\s*,/g, ",null,")
    .replace(/\[\s*,/g, "[null,")
    .replace(/,\s*\]/g, ",null]")
    .replace(/:\s*,/g, ": null,")
    .replace(/:\s*}/g, ": null}");

  try { return Function(`"use strict"; return (${src});`)(); }
  catch (e) {
    const sanitized = sanitize(sanitize(src));
    try { return Function(`"use strict"; return (${sanitized});`)(); }
    catch (e2) { return {}; }
  }
}

const cleanLabel = v => `${v || ""}`.replace(/\s*\(0x[0-9a-fA-F]+\)\s*$/, "").trim();

const asArray = v => Array.isArray(v) ? v : (v ? [v] : []);

const normalizeValue = raw => {
  const text = `${raw ?? ""}`.trim();
  return !text ? "" : text.match(/^-?\d+/)?.[0] || (text.match(/^0x([0-9a-fA-F]+)$/)?.[1] && String(parseInt(text, 16))) || text;
};

const hexSort = (a, b) => parseInt(a, 16) - parseInt(b, 16);

const getField = (obj, fieldName, def = "") => `${obj?.[fieldName] ?? def}`.trim();
const getHexAddr = (obj, field) => getField(obj, field, "");

// ZigBee data type code → command object field name mapping
const DATA_TYPE_TO_FIELD = {
  "0x10": "Boolean",
  "0x18": "Bitmap8", "0x19": "Bitmap16", "0x1a": "Bitmap24", "0x1b": "Bitmap32",
  "0x20": "Uint8", "0x21": "Uint16", "0x22": "Uint24", "0x23": "Uint32",
  "0x24": "Uint40", "0x25": "Uint48", "0x26": "Uint56", "0x27": "Uint64",
  "0x28": "Int8", "0x29": "Int16", "0x2a": "Int24", "0x2b": "Int32",
  "0x2c": "Int40", "0x2d": "Int48", "0x2e": "Int56", "0x2f": "Int64",
  "0x30": "Enum8", "0x31": "Enum16"
};

function valueForDataType(dtypeRaw, cmdObj, cursors) {
  const dtypeStr = String(dtypeRaw || "").trim();
  if (!dtypeStr) return "";
  const codeMatch = dtypeStr.match(/\((0x[0-9a-fA-F]+)\)/);
  if (!codeMatch) return "";
  const field = DATA_TYPE_TO_FIELD[codeMatch[1].toLowerCase()];
  if (!field) return "";
  const raw = cmdObj[field];
  if (raw === undefined || raw === null) return "";
  const arr = Array.isArray(raw) ? raw.filter(v => v !== undefined && v !== null && v !== "") : [raw];
  if (!arr.length) return "";
  const cursor = cursors[field] || 0;
  cursors[field] = cursor + 1;
  return normalizeValue(arr[cursor] || arr[arr.length - 1] || "");
}

const cmd = parseCommand(packet["Command String"]);
const hasZcl = "Layer ZBEE_ZCL" in cmd;
const isLinkStatus = packet["Packet Type"] === "Link Status (0x08)";

let zclMsg = null;
let filteredMsgs = [];
let currentMsgs = [];
let voltageMsgs = [];
let outgoingMsgs = [];
let thingSpeakMsgs = [];
let endMsg = null;

if (hasZcl) {
  const publishTs = Math.floor(Date.now() / 1000);
  const deviceName = getField(packet, "Device Name ZigBee Source");

  zclMsg = {
    topic: deviceName,
    payload: {
      timestamp: publishTs,
      id: msg.sub_id,
      "wpan.src": getHexAddr(packet, "Source Address"),
      "wpan.dst": getHexAddr(packet, "Destination Address"),
      "zbee.src": getHexAddr(packet, "Source Address ZigBee"),
      "zbee.dst": getHexAddr(packet, "Destination Address ZigBee"),
      topic: `ZigBee/${deviceName}`,
      payload: getField(packet, "Command String")
    }
  };

  // Extract target attributes: Active Power, RMS Current, RMS Voltage
  const attrs = asArray(cmd["Attribute"]);
  const statuses = asArray(cmd["Status"]);
  const dataTypes = asArray(cmd["Data Type"]);
  const TARGET_NAMES = { "active power": "Active Power", "rms current": "RMS Current", "rms voltage": "RMS Voltage" };
  const sequence = getField(cmd, "Sequence Number");
  const valueCursors = {};
  let filteredNo = flow.get("filteredNo") || 0;

  for (let i = 0; i < attrs.length; i++) {
    const attr = String(attrs[i] || "").trim();
    if (!attr) continue;
    const targetLabel = TARGET_NAMES[cleanLabel(attr).toLowerCase()];
    if (!targetLabel) continue;

    const dtype = String((dataTypes[i] || dataTypes[dataTypes.length - 1] || "")).trim();
    if (!dtype) continue;
    const status = String((statuses[i] || statuses[statuses.length - 1] || "")).trim();
    const value = valueForDataType(dtype, cmd, valueCursors);
    if (!value) continue;

    const dtypeClean = cleanLabel(dtype);
    const statusClean = cleanLabel(status);
    filteredMsgs.push({ payload: `${++filteredNo},${publishTs},${sequence},${targetLabel},${statusClean},${dtypeClean},${value}\n` });

    const numMatch = value.match(/-?\d+/);
    if (numMatch) {
      const numValue = Number(numMatch[0]);
      if (targetLabel === "RMS Current") currentMsgs.push({ payload: numValue, topic: targetLabel });
      else if (targetLabel === "RMS Voltage") voltageMsgs.push({ payload: numValue, topic: targetLabel });
    }
  }

  flow.set("filteredNo", filteredNo);
}

if (isLinkStatus) {
  const outgoing = flow.get("outgoingCostMap") || {};
  const src = getHexAddr(packet, "Source Address ZigBee");
  if (src && cmd["Links"] && Array.isArray(cmd["Links"])) {
    outgoing[src] ||= {};
    cmd["Links"].forEach(link => {
      if (!link || typeof link !== "object") return;
      const dst = getHexAddr(link, "Address");
      const cost = getField(link, "Outgoing Cost");
      if (dst && cost) outgoing[src][dst] = cost;
    });
    flow.set("outgoingCostMap", outgoing);
  }
}

if (msg.sub_count === 200) {
  const outgoing = flow.get("outgoingCostMap") || {};
  const sources = Object.keys(outgoing).sort(hexSort);
  let lineNo = 0;

  sources.forEach(src => {
    if (!src || !outgoing[src] || typeof outgoing[src] !== "object") return;
    Object.keys(outgoing[src]).sort(hexSort).forEach(dst => {
      if (!dst) return;
      const cost = String(outgoing[src][dst] || "").trim();
      if (cost) outgoingMsgs.push({ payload: `${++lineNo},${src},${dst},${cost}\n` });
    });
  });

  if (sources.length > 0 && outgoing[sources[0]] && typeof outgoing[sources[0]] === "object") {
    Object.keys(outgoing[sources[0]]).sort(hexSort).forEach((dst, i) => {
      if (!dst) return;
      const cost = String(outgoing[sources[0]][dst] || "").trim();
      if (cost) thingSpeakMsgs.push({ payload: { source: sources[0], destination: dst, cost: cost, order: i + 1 } });
    });
  }

  endMsg = { payload: `Processed first 200 subscribed IDs. outgoing_cost rows: ${lineNo}. ThingSpeak queue: ${thingSpeakMsgs.length}.` };
}

return [
  zclMsg,                                      // Output 1: MQTT message
  filteredMsgs.length ? filteredMsgs : null,   // Output 2: filtered_elems.csv rows
  currentMsgs.length ? currentMsgs : null,     // Output 3: RMS Current chart
  voltageMsgs.length ? voltageMsgs : null,     // Output 4: RMS Voltage chart
  outgoingMsgs.length ? outgoingMsgs : null,   // Output 5: outgoing_cost.csv rows
  thingSpeakMsgs.length ? thingSpeakMsgs : null, // Output 6: ThingSpeak API payloads
  endMsg                                       // Output 7: End message
];

const apiKey = flow.get("thingspeak_write_api_key") || env.get("THINGSPEAK_WRITE_API_KEY");
if (!apiKey) {
  node.warn("ThingSpeak key missing. Set flow.thingspeak_write_api_key or THINGSPEAK_WRITE_API_KEY.");
  return null;
}

const cost = msg.payload && msg.payload.cost !== undefined ? msg.payload.cost : "";
msg.method = "GET";
msg.url = `https://api.thingspeak.com/update?api_key=${encodeURIComponent(apiKey)}&field1=${encodeURIComponent(cost)}`;
msg.payload = "";
return msg;
